import{_ as u}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as t,c as h,f as i,q as r,D as s,O as l,j as o,g as n,k as a,X as c}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const b="/assets/docker-1.BLjk7i8q.png",C="/assets/docker-2.BqInnMTn.png",w=JSON.parse('{"title":"阿里云容器镜像服务是什么","description":"","frontmatter":{},"headers":[],"relativePath":"column/Aliyun/核心概念/阿里云的容器镜像服务讲解.md","filePath":"column/Aliyun/核心概念/阿里云的容器镜像服务讲解.md","lastUpdated":1781514912000}'),m={name:"column/Aliyun/核心概念/阿里云的容器镜像服务讲解.md"};function v(A,e,g,E,x,k){const d=t("ArticleMetadata"),p=t("Mermaid");return i(),h("div",null,[e[2]||(e[2]=r("h1",{id:"阿里云容器镜像服务是什么",tabindex:"-1"},[n("阿里云容器镜像服务是什么 "),r("a",{class:"header-anchor",href:"#阿里云容器镜像服务是什么","aria-label":'Permalink to "阿里云容器镜像服务是什么"'},"​")],-1)),s(d),e[3]||(e[3]=l('<blockquote><p>阿里云容器镜像服务是什么，这篇文章结合下面的 CodeView 项目部署 讲清楚 ACR 在部署里的作用</p></blockquote><p><img src="'+b+`" alt="" loading="lazy"></p><h2 id="一、先说结论-阿里云容器镜像服务到底是干什么的" tabindex="-1">一、先说结论：阿里云容器镜像服务到底是干什么的 <a class="header-anchor" href="#一、先说结论-阿里云容器镜像服务到底是干什么的" aria-label="Permalink to &quot;一、先说结论：阿里云容器镜像服务到底是干什么的&quot;">​</a></h2><p>很多人第一次把项目部署到阿里云 ECS 时，会卡在一个问题上：</p><p>“为什么还要多一个容器镜像服务？我不是已经有代码仓库和服务器了吗？”</p><p>如果用一句话解释：</p><p><strong>阿里云容器镜像服务 ACR，本质上是一个专门存放 Docker 镜像的仓库。</strong></p><p>它存的不是源码，而是已经构建好的运行产物。服务器真正拉取并运行的，不是 GitHub 仓库代码，而是这些镜像。</p><p>在 CodeView 这个项目里，ACR 的作用非常明确：</p><ul><li>GitHub 负责存源码</li><li>GitHub Actions 负责构建镜像</li><li>阿里云 ACR 负责存镜像</li><li>阿里云 ECS 负责拉镜像并运行</li></ul><p>只要把这四个角色分清楚，整个部署链路就会一下子清晰很多。</p><h2 id="二、为什么只有-github-和-ecs-还不够" tabindex="-1">二、为什么只有 GitHub 和 ECS 还不够 <a class="header-anchor" href="#二、为什么只有-github-和-ecs-还不够" aria-label="Permalink to &quot;二、为什么只有 GitHub 和 ECS 还不够&quot;">​</a></h2><p>很多人一开始会以为：</p><ol><li>代码在 GitHub</li><li>服务器是 ECS</li><li>GitHub Actions SSH 到 ECS</li><li>在 ECS 上执行 <code>docker compose up --build</code></li></ol><p>这样就够了。</p><p>理论上可以，但实际很容易出问题。</p><p>在 CodeView 这次部署中，真正遇到过的就是下面这些典型问题：</p><ul><li>ECS 上 Docker 服务可能还没启动</li><li>ECS 拉 Docker Hub 基础镜像可能超时</li><li>服务器网络不适合承担构建任务</li><li>构建时间长，失败点多，不稳定</li></ul><p>尤其是下面这个问题最关键：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker pull node:20-bookworm-slim</span></span>
<span class="line"><span>context deadline exceeded</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这说明一件事：<strong>服务器适合运行，不一定适合构建。</strong></p><p>所以部署方案才会演进成更稳定的结构：</p><ul><li>在 GitHub Actions 里构建镜像</li><li>把镜像推到阿里云 ACR</li><li>ECS 只负责拉镜像并运行</li></ul><p>这就是 ACR 出场的真正原因。</p><h2 id="三、什么是-镜像-为什么它不是源码" tabindex="-1">三、什么是“镜像”，为什么它不是源码 <a class="header-anchor" href="#三、什么是-镜像-为什么它不是源码" aria-label="Permalink to &quot;三、什么是“镜像”，为什么它不是源码&quot;">​</a></h2><p>想理解 ACR，先要理解“镜像”。</p><p>你可以把 Docker 镜像理解成：</p><p><strong>一个已经打包好的、可以直接运行的应用快照。</strong></p><p>它通常包含：</p><ul><li>运行环境</li><li>系统依赖</li><li>Node 版本</li><li>项目构建产物</li><li>启动命令</li><li>Nginx 配置或应用运行配置</li></ul><p>比如 CodeView 的 <code>web</code> 镜像里，放的是：</p><ul><li>前端打包后的静态资源</li><li>容器内的 Nginx</li><li><code>/api</code> 的转发配置</li></ul><p><code>server</code> 镜像里放的是：</p><ul><li>Node.js 运行环境</li><li>编译后的后端代码</li><li>启动命令</li></ul><p>所以镜像和源码的区别是：</p><ul><li><strong>源码</strong>是给开发者看的</li><li><strong>镜像</strong>是给服务器运行的</li></ul><p>GitHub 管源码，ACR 管镜像，职责完全不同。</p><h2 id="四、阿里云容器镜像服务-acr-可以把它理解成什么" tabindex="-1">四、阿里云容器镜像服务 ACR 可以把它理解成什么 <a class="header-anchor" href="#四、阿里云容器镜像服务-acr-可以把它理解成什么" aria-label="Permalink to &quot;四、阿里云容器镜像服务 ACR 可以把它理解成什么&quot;">​</a></h2><p>如果你熟悉 GitHub 仓库，可以用一个很直白的类比：</p><ul><li>GitHub 仓库：存代码</li><li>ACR 仓库：存镜像</li></ul><p>只是 ACR 存的不是：</p><ul><li><code>src/</code></li><li><code>package.json</code></li><li><code>README.md</code></li></ul><p>而是类似下面这种东西：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/web:latest</span></span>
<span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这两条不是普通地址，而是镜像引用地址。</p><p>它告诉 Docker：</p><ul><li>去哪个镜像仓库找</li><li>找哪个命名空间</li><li>找哪个镜像仓库</li><li>拉哪个标签版本</li></ul><h2 id="五、第一次看-acr-时-最容易搞混的几个概念" tabindex="-1">五、第一次看 ACR 时，最容易搞混的几个概念 <a class="header-anchor" href="#五、第一次看-acr-时-最容易搞混的几个概念" aria-label="Permalink to &quot;五、第一次看 ACR 时，最容易搞混的几个概念&quot;">​</a></h2><p>很多人不是不会用，而是第一次看到控制台时，术语太多了。</p><p>下面这几个概念，最好一次分清。</p><h3 id="_1-实例" tabindex="-1">1. 实例 <a class="header-anchor" href="#_1-实例" aria-label="Permalink to &quot;1. 实例&quot;">​</a></h3><p>你可以把实例理解成一个镜像服务的总体容器环境。</p><p>它像是“总入口”。</p><h3 id="_2-登录地址" tabindex="-1">2. 登录地址 <a class="header-anchor" href="#_2-登录地址" aria-label="Permalink to &quot;2. 登录地址&quot;">​</a></h3><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它决定了镜像仓库在哪个区域、通过哪个域名登录。</p><p>这在项目里通常对应：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACR_REGISTRY</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-命名空间" tabindex="-1">3. 命名空间 <a class="header-anchor" href="#_3-命名空间" aria-label="Permalink to &quot;3. 命名空间&quot;">​</a></h3><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codeview</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它可以理解成镜像仓库的一层分组。</p><p>这在项目里通常对应：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACR_NAMESPACE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-镜像仓库" tabindex="-1">4. 镜像仓库 <a class="header-anchor" href="#_4-镜像仓库" aria-label="Permalink to &quot;4. 镜像仓库&quot;">​</a></h3><p>例如：</p><ul><li><code>server</code></li><li><code>web</code></li></ul><p>合起来就形成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codeview/server</span></span>
<span class="line"><span>codeview/web</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_5-标签-tag" tabindex="-1">5. 标签 Tag <a class="header-anchor" href="#_5-标签-tag" aria-label="Permalink to &quot;5. 标签 Tag&quot;">​</a></h3><p>例如：</p><ul><li><code>latest</code></li><li><code>b5a114a</code></li><li><code>9812a71</code></li></ul><p>标签的作用是标识镜像版本。</p><p>所以完整镜像地址通常长这样：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它的拆解方式是：</p><ul><li>注册表地址：<code>crpi-********.cn-shanghai.personal.cr.aliyuncs.com</code></li><li>命名空间：<code>codeview</code></li><li>仓库名：<code>server</code></li><li>标签：<code>latest</code></li></ul><p>只要把这四层看明白，ACR 基本就不再神秘。</p><h2 id="六、结合-codeview-看-为什么我们最终选了-acr" tabindex="-1">六、结合 CodeView 看，为什么我们最终选了 ACR <a class="header-anchor" href="#六、结合-codeview-看-为什么我们最终选了-acr" aria-label="Permalink to &quot;六、结合 CodeView 看，为什么我们最终选了 ACR&quot;">​</a></h2><p>CodeView 的最终部署方案不是：</p><ul><li>ECS 自己构建镜像</li></ul><p>而是：</p><ul><li>GitHub Actions 构建镜像</li><li>推送到阿里云 ACR</li><li>ECS 从 ACR 拉取镜像</li></ul><p>原因很现实。</p><h3 id="_1-ecs-只保留运行职责" tabindex="-1">1. ECS 只保留运行职责 <a class="header-anchor" href="#_1-ecs-只保留运行职责" aria-label="Permalink to &quot;1. ECS 只保留运行职责&quot;">​</a></h3><p>服务器越少做事，线上就越稳定。</p><p>如果 ECS 既要：</p><ul><li>拉源码</li><li>安装依赖</li><li>本地 build</li><li>构建 Docker 镜像</li><li>再启动服务</li></ul><p>那它的失败点会非常多。</p><p>改成：</p><ul><li>ECS 只拉镜像</li><li>ECS 只运行 compose</li></ul><p>以后排查问题会轻很多。</p><h3 id="_2-acr-离-ecs-更近-更适合阿里云内部部署链路" tabindex="-1">2. ACR 离 ECS 更近，更适合阿里云内部部署链路 <a class="header-anchor" href="#_2-acr-离-ecs-更近-更适合阿里云内部部署链路" aria-label="Permalink to &quot;2. ACR 离 ECS 更近，更适合阿里云内部部署链路&quot;">​</a></h3><p>在这次实操里，Docker Hub 拉基础镜像就超时过。继续坚持完全依赖 Docker Hub，会把部署稳定性压在外部网络上。</p><p>而 ACR 作为阿里云自己的镜像仓库服务，更适合作为阿里云 ECS 的上游镜像来源。</p><h3 id="_3-更适合-ci-cd" tabindex="-1">3. 更适合 CI/CD <a class="header-anchor" href="#_3-更适合-ci-cd" aria-label="Permalink to &quot;3. 更适合 CI/CD&quot;">​</a></h3><p>一旦把“构建”和“运行”拆开，自动化流程就会很清晰：</p>`,98)),(i(),o(c,null,{default:a(()=>[s(p,{id:"mermaid-555",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22%E5%BC%80%E5%8F%91%E8%80%85%20push%20%E4%BB%A3%E7%A0%81%22%5D%20--%3E%20B%5B%22GitHub%20Actions%20%E6%9E%84%E5%BB%BA%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22%E6%8E%A8%E9%80%81%E9%95%9C%E5%83%8F%E5%88%B0%20ACR%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22ECS%20%E6%8B%89%E5%8F%96%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20D%20--%3E%20E%5B%22Docker%20Compose%20%E5%90%AF%E5%8A%A8%E6%9C%8D%E5%8A%A1%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=l('<p>这就是标准的 CI/CD 思路。</p><h2 id="七、codeview-在-acr-里实际存了什么" tabindex="-1">七、CodeView 在 ACR 里实际存了什么 <a class="header-anchor" href="#七、codeview-在-acr-里实际存了什么" aria-label="Permalink to &quot;七、CodeView 在 ACR 里实际存了什么&quot;">​</a></h2><p>在 CodeView 这套部署里，ACR 里主要有两个镜像：</p><p><img src="'+C+'" alt="" loading="lazy"></p><h3 id="_1-server-镜像" tabindex="-1">1. <code>server</code> 镜像 <a class="header-anchor" href="#_1-server-镜像" aria-label="Permalink to &quot;1. `server` 镜像&quot;">​</a></h3><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它负责：</p><ul><li>Node.js 后端 API</li><li>GitHub 数据同步</li><li>SQLite 数据访问</li><li>定时任务恢复和执行</li></ul><h3 id="_2-web-镜像" tabindex="-1">2. <code>web</code> 镜像 <a class="header-anchor" href="#_2-web-镜像" aria-label="Permalink to &quot;2. `web` 镜像&quot;">​</a></h3><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/web:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它负责：</p><ul><li>承载前端静态资源</li><li>容器内 Nginx 提供页面访问</li><li><code>/api</code> 转发给 <code>server:3101</code></li></ul><p>所以 ACR 不是只放一个“大镜像”，而是按服务维度拆开管理。</p><p>这也意味着以后如果项目继续演进，增加更多服务时，ACR 里只是多几个镜像仓库而已，结构不会乱。</p><h2 id="八、github、acr、ecs-三者到底怎么配合" tabindex="-1">八、GitHub、ACR、ECS 三者到底怎么配合 <a class="header-anchor" href="#八、github、acr、ecs-三者到底怎么配合" aria-label="Permalink to &quot;八、GitHub、ACR、ECS 三者到底怎么配合&quot;">​</a></h2><p>如果把这三个角色画成一条链路，会更容易理解：</p>',18)),(i(),o(c,null,{default:a(()=>[s(p,{id:"mermaid-639",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20Dev%20as%20%E5%BC%80%E5%8F%91%E8%80%85%0A%20%20%20%20participant%20GH%20as%20GitHub%0A%20%20%20%20participant%20GA%20as%20GitHub%20Actions%0A%20%20%20%20participant%20ACR%20as%20%E9%98%BF%E9%87%8C%E4%BA%91%20ACR%0A%20%20%20%20participant%20ECS%20as%20%E9%98%BF%E9%87%8C%E4%BA%91%20ECS%0A%0A%20%20%20%20Dev-%3E%3EGH%3A%20push%20%E4%BB%A3%E7%A0%81%0A%20%20%20%20GH-%3E%3EGA%3A%20%E8%A7%A6%E5%8F%91%20workflow%0A%20%20%20%20GA-%3E%3EGA%3A%20%E6%9E%84%E5%BB%BA%20server%20%2F%20web%20%E9%95%9C%E5%83%8F%0A%20%20%20%20GA-%3E%3EACR%3A%20push%20%E9%95%9C%E5%83%8F%0A%20%20%20%20GA-%3E%3EECS%3A%20SSH%20%E7%99%BB%E5%BD%95%E5%B9%B6%E6%89%A7%E8%A1%8C%E9%83%A8%E7%BD%B2%E5%91%BD%E4%BB%A4%0A%20%20%20%20ECS-%3E%3EACR%3A%20docker%20pull%20%E9%95%9C%E5%83%8F%0A%20%20%20%20ECS-%3E%3EECS%3A%20docker%20compose%20up%20-d%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[n(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=l(`<p>整个流程里：</p><ul><li>GitHub 是代码源</li><li>GitHub Actions 是构建器</li><li>ACR 是镜像仓库</li><li>ECS 是运行环境</li></ul><p>你会发现，ACR 正好卡在“构建完成”和“正式运行”之间。</p><p>这就是它最核心的定位：</p><p><strong>镜像中转站，也是正式发布源。</strong></p><h2 id="九、如果没有-acr-会发生什么" tabindex="-1">九、如果没有 ACR，会发生什么 <a class="header-anchor" href="#九、如果没有-acr-会发生什么" aria-label="Permalink to &quot;九、如果没有 ACR，会发生什么&quot;">​</a></h2><p>如果不用 ACR，常见就只剩两种方案。</p><h3 id="方案一-ecs-本地-build" tabindex="-1">方案一：ECS 本地 build <a class="header-anchor" href="#方案一-ecs-本地-build" aria-label="Permalink to &quot;方案一：ECS 本地 build&quot;">​</a></h3><p>问题是：</p><ul><li>依赖服务器环境</li><li>容易受网络影响</li><li>构建慢</li><li>部署时长更长</li><li>失败点更多</li></ul><h3 id="方案二-继续用-docker-hub-当私有发布源" tabindex="-1">方案二：继续用 Docker Hub 当私有发布源 <a class="header-anchor" href="#方案二-继续用-docker-hub-当私有发布源" aria-label="Permalink to &quot;方案二：继续用 Docker Hub 当私有发布源&quot;">​</a></h3><p>也不是不行，但在阿里云 ECS 场景下，未必是最稳的做法。</p><p>尤其当你已经确定部署目标就是阿里云时，把镜像发布源放到阿里云体系内，通常会更顺手。</p><p>所以对于 CodeView 这种“个人项目 + ECS + Docker Compose”的组合，ACR 是一个非常合适的选择。</p><h2 id="十、对新手来说-acr-最重要的不是-学会所有功能-而是先理解它的最小用途" tabindex="-1">十、对新手来说，ACR 最重要的不是“学会所有功能”，而是先理解它的最小用途 <a class="header-anchor" href="#十、对新手来说-acr-最重要的不是-学会所有功能-而是先理解它的最小用途" aria-label="Permalink to &quot;十、对新手来说，ACR 最重要的不是“学会所有功能”，而是先理解它的最小用途&quot;">​</a></h2><p>第一次接触 ACR，没必要上来就研究很复杂的企业级能力。</p><p>对个人项目来说，你先把最小用途理解清楚就够了：</p><ol><li>创建实例</li><li>创建命名空间</li><li>创建镜像仓库</li><li>让 GitHub Actions 登录 ACR</li><li>把镜像 push 上去</li><li>让 ECS 从 ACR pull 下来</li></ol><p>只要完成这六步，ACR 就已经发挥作用了。</p><p>换句话说，<strong>你不需要把 ACR 当成一个很复杂的平台，先把它当成“阿里云上的 Docker 镜像仓库”就行。</strong></p><h2 id="十一、codeview-这套方案里-acr-的配置长什么样" tabindex="-1">十一、CodeView 这套方案里，ACR 的配置长什么样 <a class="header-anchor" href="#十一、codeview-这套方案里-acr-的配置长什么样" aria-label="Permalink to &quot;十一、CodeView 这套方案里，ACR 的配置长什么样&quot;">​</a></h2><p>在 CodeView 里，实际使用到的关键配置大致如下：</p><h3 id="_1-github-secrets" tabindex="-1">1. GitHub Secrets <a class="header-anchor" href="#_1-github-secrets" aria-label="Permalink to &quot;1. GitHub Secrets&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACR_REGISTRY</span></span>
<span class="line"><span>ACR_NAMESPACE</span></span>
<span class="line"><span>ACR_USERNAME</span></span>
<span class="line"><span>ACR_PASSWORD</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_2-生产环境-env" tabindex="-1">2. 生产环境 <code>.env</code> <a class="header-anchor" href="#_2-生产环境-env" aria-label="Permalink to &quot;2. 生产环境 \`.env\`&quot;">​</a></h3><div class="language-env vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SERVER_IMAGE=crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span>
<span class="line"><span>WEB_IMAGE=crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/web:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_3-workflow-的核心逻辑" tabindex="-1">3. Workflow 的核心逻辑 <a class="header-anchor" href="#_3-workflow-的核心逻辑" aria-label="Permalink to &quot;3. Workflow 的核心逻辑&quot;">​</a></h3><p>可以概括成下面几步：</p><ol><li><code>docker login</code> 登录 ACR</li><li>构建 <code>server</code> 镜像</li><li>构建 <code>web</code> 镜像</li><li>推送两个镜像到 ACR</li><li>ECS 部署时执行 <code>docker compose pull</code></li><li>ECS 再执行 <code>docker compose up -d</code></li></ol><p>所以 ECS 侧并不关心源码构建细节，它只认镜像地址。</p><h2 id="十二、如果你换了自己的-acr-哪些镜像地址必须一起改" tabindex="-1">十二、如果你换了自己的 ACR，哪些镜像地址必须一起改 <a class="header-anchor" href="#十二、如果你换了自己的-acr-哪些镜像地址必须一起改" aria-label="Permalink to &quot;十二、如果你换了自己的 ACR，哪些镜像地址必须一起改&quot;">​</a></h2><p>这是实际部署里非常容易漏掉的一步。</p><p>很多人已经在阿里云上创建好了自己的 ACR：</p><ul><li>自己的实例</li><li>自己的命名空间</li><li>自己的 <code>server</code> 和 <code>web</code> 仓库</li></ul><p>但如果项目里还保留着原来的镜像地址，ECS 拉取的仍然不是你自己的镜像，部署自然会出问题。</p><p>在 CodeView 这套方案里，<strong>镜像地址至少有两个地方必须同步改</strong>。</p><h3 id="_1-github-actions-里的-acr-配置" tabindex="-1">1. GitHub Actions 里的 ACR 配置 <a class="header-anchor" href="#_1-github-actions-里的-acr-配置" aria-label="Permalink to &quot;1. GitHub Actions 里的 ACR 配置&quot;">​</a></h3><p>GitHub Actions 构建和推送镜像时，用的是这些 Secrets：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACR_REGISTRY</span></span>
<span class="line"><span>ACR_NAMESPACE</span></span>
<span class="line"><span>ACR_USERNAME</span></span>
<span class="line"><span>ACR_PASSWORD</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>比如你自己的 ACR 是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACR_REGISTRY=crpi-xxxxxxxx.cn-shanghai.personal.cr.aliyuncs.com</span></span>
<span class="line"><span>ACR_NAMESPACE=codeview</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>那么 workflow 在 push 镜像时，最终就会生成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-xxxxxxxx.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span>
<span class="line"><span>crpi-xxxxxxxx.cn-shanghai.personal.cr.aliyuncs.com/codeview/web:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>所以第一步不是改代码，而是先确认 GitHub 仓库里的 Secrets 已经换成你自己的值。</p><h3 id="_2-ecs-共享环境文件里的镜像地址" tabindex="-1">2. ECS 共享环境文件里的镜像地址 <a class="header-anchor" href="#_2-ecs-共享环境文件里的镜像地址" aria-label="Permalink to &quot;2. ECS 共享环境文件里的镜像地址&quot;">​</a></h3><p>ECS 启动 Compose 时，真正读取的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/www/codeview/shared/.env</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>里面这两个值必须和你自己的 ACR 保持一致：</p><div class="language-env vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SERVER_IMAGE=crpi-xxxxxxxx.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span>
<span class="line"><span>WEB_IMAGE=crpi-xxxxxxxx.cn-shanghai.personal.cr.aliyuncs.com/codeview/web:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>也就是说：</p><ul><li>GitHub Actions 决定“镜像推到哪里”</li><li>ECS <code>.env</code> 决定“服务器从哪里拉镜像”</li></ul><p>这两个地方只改一个都不够，必须一起对上。</p><h3 id="_3-最容易忽略的错误场景" tabindex="-1">3. 最容易忽略的错误场景 <a class="header-anchor" href="#_3-最容易忽略的错误场景" aria-label="Permalink to &quot;3. 最容易忽略的错误场景&quot;">​</a></h3><p>最常见的错误有三种：</p><h4 id="场景一-secrets-改了-ecs-env-没改" tabindex="-1">场景一：Secrets 改了，ECS <code>.env</code> 没改 <a class="header-anchor" href="#场景一-secrets-改了-ecs-env-没改" aria-label="Permalink to &quot;场景一：Secrets 改了，ECS \`.env\` 没改&quot;">​</a></h4><p>结果：</p><ul><li>GitHub Actions 已经把新镜像推到你自己的 ACR</li><li>但 ECS 还在按旧地址拉镜像</li></ul><p>表现通常是：</p><ul><li><code>docker compose pull</code> 拉不到镜像</li><li>或者拉到的不是你刚构建的新版本</li></ul><h4 id="场景二-ecs-env-改了-secrets-没改" tabindex="-1">场景二：ECS <code>.env</code> 改了，Secrets 没改 <a class="header-anchor" href="#场景二-ecs-env-改了-secrets-没改" aria-label="Permalink to &quot;场景二：ECS \`.env\` 改了，Secrets 没改&quot;">​</a></h4><p>结果：</p><ul><li>ECS 去你自己的 ACR 拉镜像</li><li>但 GitHub Actions 其实还在往旧 ACR 推</li></ul><p>表现通常是：</p><ul><li>服务器一直找不到对应 tag</li><li>你以为已经发布了，实际上新镜像根本没进你现在用的仓库</li></ul><h4 id="场景三-只改了仓库名-没有改命名空间或-registry" tabindex="-1">场景三：只改了仓库名，没有改命名空间或 registry <a class="header-anchor" href="#场景三-只改了仓库名-没有改命名空间或-registry" aria-label="Permalink to &quot;场景三：只改了仓库名，没有改命名空间或 registry&quot;">​</a></h4><p>例如把：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codeview/server</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>改了，但：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-xxxxx.cn-shanghai.personal.cr.aliyuncs.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者命名空间 <code>codeview</code> 没同步改对。</p><p>结果一样会导致镜像地址不完整或不匹配。</p><h3 id="_4-一个最稳的检查办法" tabindex="-1">4. 一个最稳的检查办法 <a class="header-anchor" href="#_4-一个最稳的检查办法" aria-label="Permalink to &quot;4. 一个最稳的检查办法&quot;">​</a></h3><p>可以按下面顺序检查：</p><ol><li>看 GitHub Secrets 里的 <code>ACR_REGISTRY</code> 和 <code>ACR_NAMESPACE</code></li><li>看 ECS <code>/var/www/codeview/shared/.env</code> 里的 <code>SERVER_IMAGE</code> 和 <code>WEB_IMAGE</code></li><li>确认两边拼出来的镜像地址完全一致</li></ol><p>例如当前项目正确对齐后应该像这样：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/server:latest</span></span>
<span class="line"><span>crpi-********.cn-shanghai.personal.cr.aliyuncs.com/codeview/web:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>只要这两边不一致，部署大概率就会出问题。</p><h2 id="十三、为什么说-acr-让部署更像-发布-而不是-现场组装" tabindex="-1">十三、为什么说 ACR 让部署更像“发布”，而不是“现场组装” <a class="header-anchor" href="#十三、为什么说-acr-让部署更像-发布-而不是-现场组装" aria-label="Permalink to &quot;十三、为什么说 ACR 让部署更像“发布”，而不是“现场组装”&quot;">​</a></h2><p>这是我觉得最值得强调的一点。</p><p>没有 ACR 时，部署更像：</p><ul><li>到服务器上装环境</li><li>现场拉依赖</li><li>现场 build</li><li>现场拼装</li><li>希望它能一次成功</li></ul><p>而有了 ACR 之后，部署变成了：</p><ul><li>先在 CI 中把成品打包好</li><li>把成品放进镜像仓库</li><li>服务器只负责拿成品运行</li></ul><p>这两种思路差别非常大。</p><p>前者像“现场施工”，后者像“工厂预制 + 现场安装”。</p><p>对真实线上环境来说，后者显然更稳。</p><h2 id="十四、这篇文章最适合哪些人看" tabindex="-1">十四、这篇文章最适合哪些人看 <a class="header-anchor" href="#十四、这篇文章最适合哪些人看" aria-label="Permalink to &quot;十四、这篇文章最适合哪些人看&quot;">​</a></h2><p>这篇文章特别适合下面几类人：</p><ul><li>第一次接触阿里云 ECS 部署的人</li><li>知道 Docker，但不理解镜像仓库作用的人</li><li>已经有 GitHub Actions，但不清楚 ACR 为什么还要接进来的人</li><li>准备用 Docker Compose 部署个人项目的人</li></ul><p>如果你当前的项目和 CodeView 类似：</p><ul><li>前后端分离</li><li>服务数量不多</li><li>用单台 ECS 部署</li><li>希望提交代码后自动更新</li></ul><p>那么“GitHub Actions + ACR + ECS + Docker Compose”这条链路，基本就是一个很合理的起点。</p><h2 id="十五、结论" tabindex="-1">十五、结论 <a class="header-anchor" href="#十五、结论" aria-label="Permalink to &quot;十五、结论&quot;">​</a></h2><p>阿里云容器镜像服务 ACR，并不是一个“额外增加复杂度”的东西，恰恰相反，它是在帮你把部署流程拆清楚。</p><p>在 CodeView 这次实践里，ACR 解决的不是一个抽象问题，而是非常具体的两个痛点：</p><ol><li>ECS 不适合承担镜像构建职责。</li><li>需要一个稳定的镜像发布源，让 ECS 只做拉取和运行。</li></ol><p>所以如果你还在纠结“我的项目到底要不要接 ACR”，可以先用最朴素的判断标准：</p><p>如果你希望：</p><ul><li>自动部署</li><li>服务器少干活</li><li>部署链路更稳定</li><li>镜像版本更清晰</li></ul><p>那 ACR 基本就是值得接入的。</p><p>对于 CodeView 这种部署到阿里云 ECS 的项目来说，ACR 不是可有可无的配角，而是整条部署链路里非常关键的一环。</p><h2 id="十六、延伸阅读" tabindex="-1">十六、延伸阅读 <a class="header-anchor" href="#十六、延伸阅读" aria-label="Permalink to &quot;十六、延伸阅读&quot;">​</a></h2><p>如果你想继续看完整的 CodeView 上线过程，可以结合这篇文档一起看：</p><ul><li><a href="./CodeView部署实战博客">CodeView 部署实战博客</a></li><li><a href="./Docker Compose部署到ECS说明">Docker Compose 部署到 ECS 说明</a></li></ul>`,104))])}const S=u(m,[["render",v]]);export{w as __pageData,S as default};
